INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('行政专员/助理 - 三亚（社招）', '文化传媒 / 广告', '三亚', '民营企业', 5000, 6000, '熟练使用Office办公软件', '思路清晰，考虑问题细致，责任心强，为人正直，情商高，可妥善处理各方关系', 1, '友好', '1. 日常对接属地园区，以及各类政府主管部门，参加会议，申请奖励等；2. 协助公司财务人员处理财税事宜，如费用报销单据的初步审核、付款申请单的整理；3. 对接公司承租的办公以及居住用房的物业、出租方等，保证房屋的正常使用，完成基础办公区域卫生维护；4. 负责物品采买、机场接送机', '行政事务支持、接待外联、财务辅助支持', '本科及以上', '无强制专业限制', '经验不限', '社招（应届生可投）', '党员优先；有政府对接、财税相关经验', '5k-6k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员 - 大连（社招）', '金融', '大连', '民营企业', 4000, 9000, '熟练使用Office办公软件', '沟通和协调能力强，情商高；性格开朗，形象气质佳，外向', 1, '友好', '1. 负责带客户去银行办理征信相关业务，跟进行程及费用报销；2. 负责配合销售部完成录单工作；3. 对接银行和客户，协调处理相关业务问题', '行政事务支持、跨部门协调、接待外联', '大专及以上', '无强制专业限制', '经验不限', '社招（应届生可投）', '有金融行业、银行对接相关经验', '4k-9k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员 - 十堰（社招）', '制造', '十堰', '民营企业', 3000, 5000, '熟练使用Office办公软件', '有较强的沟通协调能力；工作认真负责，执行力强', 1, '友好', '1. 完成公司日常的人员招聘、培训、薪酬、劳动关系及人事档案管理；2. 协助监督控制各部门绩效评价过程并不断完善绩效管理体系；3. 负责有关人力资源方面的数据整理、汇编和制作与管理；4. 负责公司企业文化、人力资源及行政有关制度在项目上的落实；5. 完成日常行政事务工作，包括行政公文管理、会议管理、办公物品管理、办公费用操作与执行等；6. 协调公司各部门行政方面工作之间的关系，以及与合作单位之间的关系；7. 协助公司相关活动的开展和执行；8. 完成领导交办的其他工作事项', '行政事务支持、招聘全流程执行、薪酬绩效支持、员工关系支持、OD 组织发展支持', '大专及以上', '无强制专业限制', '1-3年，有人事行政相关工作经验', '社招（应届生可投）', '有人力资源管理师相关证书；有制造业人事行政工作经验', '3k-5k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员 - 佛山（实习）', '文化传媒 / 广告', '佛山', '民营企业', 150, 200, '1. 熟练使用Office办公软件；2. 有驾驶证，能独立开车', '工作认真负责，执行力强，具备良好的沟通协调能力，能适应出差', 1, '友好', '1. 负责公司行政相关事务（包括文档管理、制度管理、日常支出管理等）；2. 负责公司项目执行相关助理后勤，提供相关后勤保障；3. 熟悉公司业务，负责相关招聘邀约；4. 负责公司部分简要财务事宜；5. 配合公司其他部门的相关工作，处理相关事宜；6. 可跟团队出差兼顾公司业务；7. 负责公司交代的其他事项', '行政事务支持、招聘辅助、财务辅助、后勤保障', '大专及以上（能力优秀者除外）', '财务会计专业优先', '可实习6个月，每周到岗5天，经验不限', '日常实习', '有驾驶证；财务会计相关专业；有行政相关实习经验', '150-200元/天', '46078', '46112', 'https://www.shixiseng.com/intern/inn_c1sin3ucafd3?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）'), ('行政专员 - 合肥（实习）', '房地产 / 建筑', '合肥', '民营企业', 150, 300, '熟练使用Office办公软件', '形象端正，性格开朗，有良好的沟通表达能力、亲和力，具有良好的团队合作精神', 1, '友好', '1. 负责店面日常行政工作，日常数据维护；2. 配合商圈经理日常门店工作；3. 负责部门招聘工作', '行政事务支持、招聘全流程执行、门店运营支持', '大专及以上', '无强制专业限制', '年龄20-30周岁，可实习6个月，每周到岗6天，经验不限', '日常实习', '有房产行业、招聘相关经验', '150-300元/天', '45082', '46112', 'https://www.shixiseng.com/intern/inn_hdv2g1hqwdqv?pcm=pc_SearchList', '行政类', '甲方（企业自有 HR 岗）');